using Xunit;namespace IntegraRP.Tests;public sealed class ArchitectureTests{[Fact]public void Domain_Nao_Deve_Referenciar_Camadas_Externas(){var refs=typeof(IntegraRP.Domain.Tenancy.Tenant).Assembly.GetReferencedAssemblies().Select(x=>x.Name).ToArray();Assert.DoesNotContain("IntegraRP.Infrastructure",refs);Assert.DoesNotContain("IntegraRP.Api",refs);Assert.DoesNotContain("Dapper",refs);Assert.DoesNotContain("Npgsql",refs);}}
